<?php require __DIR__ . '/bootstrap.php'; $instanceId=(int)($_GET['instance_id']??0); if(!$instanceId) exit('Instância obrigatória.'); $auth->requireInstanceAccess($instanceId); $cards=$financial->cards($instanceId); $purchases=$financial->purchases($instanceId); $bills=$financial->bills($instanceId); ?><!doctype html><html lang="pt-br"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Cartões</title><link rel="stylesheet" href="<?= e(base_path('assets/ui.css')) ?>"></head><body><div class="wrap"><?php financial_nav($instanceId,'cards'); ?><div class="card"><h1 class="headline">Cartões</h1><div class="list"><?php foreach($cards as $c): ?><div class="member"><div class="meta"><strong><?= e($c['name']) ?></strong><span class="muted"><?= e((string)$c['bank_name']) ?></span></div><span class="tag">R$ <?= number_format((float)$c['credit_limit'],2,',','.') ?></span></div><?php endforeach; ?></div></div><div class="grid"><div class="card"><h2>Compras</h2><div class="list"><?php foreach($purchases as $p): ?><div class="member"><div class="meta"><strong><?= e($p['description']) ?></strong><span class="muted"><?= e($p['card_name']) ?> · <?= (int)$p['installments_count'] ?>x</span></div><span class="tag">R$ <?= number_format((float)$p['total_amount'],2,',','.') ?></span></div><?php endforeach; ?></div></div><div class="card"><h2>Faturas</h2><div class="list"><?php foreach($bills as $b): ?><div class="member"><div class="meta"><strong><?= e($b['card_name']) ?> · <?= (int)$b['reference_month'] ?>/<?= (int)$b['reference_year'] ?></strong><span class="muted">Venc. <?= e($b['due_date']) ?></span></div><span class="tag">R$ <?= number_format((float)$b['total_amount'],2,',','.') ?></span></div><?php endforeach; ?></div></div></div></div></body></html>
